import { readFileSync, writeFileSync } from "node:fs";
import { join } from "node:path";

export type User = {
  id: string;
  nama: string;
  jabatan: string;
  site: string;
  siteId: string;
  pos: string;
  email: string;
};

export type Shift = {
  id: string;
  label: string;
  name?: string;
  startTime: string;
  endTime: string;
  checkInWindowMinutes: number;
};

export type Site = {
  id: string;
  name: string;
  lat: number;
  lng: number;
  radiusMeters: number;
};

export type Attendance = {
  id: string;
  userId: string;
  date: string;
  shiftId: string;
  checkIn: string;
  checkOut: string | null;
  status: string;
  lat: number;
  lng: number;
  photoUrl?: string;
  checkOutPhotoUrl?: string | null;
};

export type Report = {
  id: string;
  userId: string;
  type: string;
  title: string;
  status: string;
  date: string;
  shiftId: string;
  notes?: string;
  createdAt: string;
  [key: string]: unknown;
};

export type Incident = {
  id: string;
  userId: string;
  type: string;
  title: string;
  status: string;
  date: string;
  location: string;
  lat: number;
  lng: number;
  createdAt: string;
  chronological: string;
  timeline: Record<string, unknown>[];
  [key: string]: unknown;
};

export type ChecklistItem = {
  id: string;
  label: string;
  done: boolean;
};

export type Checklist = {
  id: string;
  userId: string;
  date: string;
  shiftId: string;
  items: ChecklistItem[];
  totalDone: number;
  total: number;
};

// ─── Phase 4: Profile & Personnel ─────────────────────────────────────────────

export type PersonnelProfile = {
  id: string;              // same as userId
  employeeNumber: string;
  name: string;
  photoUrl: string | null;
  level: string;           // e.g. "Senior", "Supervisor"
  status: string;          // "aktif" | "non-aktif" | dll
  workLocation: string;
  workUnit: string;
  position: string;
  bpjsKesehatan: string | null;
  bpjsKetenagakerjaan: string | null;
};

export type PersonalInfo = {
  id: string;
  userId: string;
  nik: string;
  birthPlace: string;
  birthDate: string;       // YYYY-MM-DD
  gender: string;          // "laki-laki" | "perempuan"
  phone: string;
  email: string;
  address: string;
};

export type EmploymentInfo = {
  id: string;
  userId: string;
  joinDate: string;        // YYYY-MM-DD
  contractStatus: string;  // "tetap" | "kontrak" | "magang"
  contractExpiry: string | null;
  supervisorName: string;
  workArea: string;
  workLocation: string;
  workUnit: string;
};

export type PersonnelDocument = {
  id: string;
  userId: string;
  type: string;            // "ktp" | "sim" | "bpjs-kesehatan" | dll
  label: string;
  documentNumber: string | null;
  issueDate: string | null;
  expiryDate: string | null;
  status: string;          // "aktif" | "akan-kadaluarsa" | "kadaluarsa"
  fileUrl: string | null;
  daysUntilExpiry: number | null;
};

export type TrainingData = {
  id: string;
  userId: string;
  skiCertifications: Record<string, unknown>[];
  securityCertifications: Record<string, unknown>[];
  trainingHistory: Record<string, unknown>[];
};

export type DisciplineData = {
  id: string;
  userId: string;
  warningLetters: Record<string, unknown>[];
  achievements: Record<string, unknown>[];
};

export type DbSchema = {
  users: User[];
  shifts: Shift[];
  sites: Site[];
  attendances: Attendance[];
  reports: Report[];
  checklists: Checklist[];
  incidents: Incident[];
  // ── Phase 4 ──────────────────────────────────────────
  profile: PersonnelProfile[];
  personalInfo: PersonalInfo[];
  employmentInfo: EmploymentInfo[];
  documents: PersonnelDocument[];
  training: TrainingData[];
  discipline: DisciplineData[];
};

const DB_PATH = join(process.cwd(), "db.json");

